    // minimal HTTP server helper for TC17–TC19
    private static class SimpleHttpServer extends Thread {
        private final int port;
        private final int status;
        private final String body;
        private final String contentType;
        private volatile boolean ready = false;

        SimpleHttpServer(int port, int status, String body, String contentType) {
            this.port = port; this.status = status; this.body = body; this.contentType = contentType;
        }
        public void run() {
            try (ServerSocket server = new ServerSocket(port)) {
                ready = true;
                Socket client = server.accept();
                String responseLine = "HTTP/1.1 " + status + " " + (status==200?"OK":"Error");
                String ct = contentType!=null?"Content-Type: "+contentType:"";
                String resp = responseLine + "\r\n" + ct + "\r\n\r\n" + body;
                client.getOutputStream().write(resp.getBytes(StandardCharsets.UTF_8));
                client.close();
            } catch (IOException ignored) {}
        }
        public void awaitReady() throws InterruptedException { while(!ready) Thread.sleep(10); }
    }

    @Test
    @DisplayName("TC17: parse(URL, timeout) with valid HTTP URL returns parsed HTML")
    public void test_TC17() throws Exception {
        int port = 8087;
        SimpleHttpServer srv = new SimpleHttpServer(port, 200, "<p>OK</p>", "text/html");
        srv.start();
        srv.awaitReady();
        URL url = new URL("http://localhost:" + port + "/");
        Document doc = Jsoup.parse(url, 1000);
        assertEquals("<p>OK</p>", doc.body().html());
    }

